                                <option value="percent_inc">Tăng giá theo %</option>
                                <option value="percent_dec">Giảm giá theo %</option>
                                <option value="amount_inc">Tăng giá theo số tiền (VND)</option>
                                <option value="amount_dec">Giảm giá theo số tiền (VND)</option>
                            </select>
                            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16}/>
                        </div>
                    </div>
                    <div className="flex-1 min-w-[150px]">
                        <label className="block text-sm font-bold text-slate-700 mb-1">Giá trị</label>
